module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);


reg [2:0] ST_cr, ST_nr;

always @(posedge CLK or posedge RST) begin
    if (RST) ST_cr <= s0; else ST_cr <= ST_nr;
end

always @(*) begin
    case(ST_cr)
        s0: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s0;
        end
        s1: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s2;
        end
        s2: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s3;
        end
        s3: begin
            if(IN==1) ST_nr=s4;
            else ST_nr=s0;
        end
        s4: begin
            if(IN==1) ST_nr=s5;
            else ST_nr=s2;
        end
        s5: begin
            if(IN==1) ST_nr=s1;
            else ST_nr=s2;
        end
        default: ST_nr=s0;
    endcase
end

assign MATCH = (RST)? 0 :
               ((ST_cr==s4)&&(IN==1))? 1 : 0;
endmodule
